## 二、new&delete expression

### 1、new expression

对于代码：

```c++
Complex* pc = new Complex(1,2);
```

编译器会转换为：

```c++
Complex *pc;
try{
    //分配内存大小
    void* mem = operator new( sizeof(Complex) ); //allocate
    //强制类型转换
    pc = static_cast<Complex*>(mem);             //cast
    //调用目标类型的构造函数
    pc->Complex::Complex(1,2);                   //constract
    /*
    注意：只有编译器才可以像上面那样直接呼叫ctor(构造函数)
    欲直接调用ctor，可以运用placement new：
    new(p)Complex(1,2);
    */
}
catch( std::bad_alloc ){
    //若allocation失败就不执行constructor
}
```

opeator new源码（VC）:

```c++
void *operator new(size_t size,const std::nothrow_t&)_THROW0()
{
    //const std::nothrow_t& 函数保证不抛出异常
    //该结构用作函数operator new参数，表示函数应该返回一个空指针来报告分配失败。而不是抛出异常。
	//try to allocate size bytes
    void *p;
    //内部调用了malloc函数
    while((p=malloc(size))==0)
    {
        //buy more memory ot return null pointer
        _TRY_BEGIN
            if(_callnewh(size)==0) break;
        _CATCH(std::bad_alloc) return(0);
        _CATCH_END
    }
    return (p);
}
```

![](https://raw.githubusercontent.com/renmale-lv/BlogImage/main/202211291953663.jpg)

### 2、delete expression

对于代码：

```c++
Complex* pc = new Complex(1,2);
......
delete pc;
```

编译器会转为：

```c++
pc->~Complex();                 //先析构
//不同于new expression，这里可以直接调用析构函数
operatoe delete(pc);            //然后释放内存
```

opeator new源码（VC）:

```c++
//.../vc98/crt/src/delop.cpp
void__cdecl operator delete(void *p)_THROW0(){
    //free an aallocated object
    free(p);
    //内部调用了free函数
}
```

![](https://raw.githubusercontent.com/renmale-lv/BlogImage/main/202211291953220.jpg)

### 3、Ctor & Dtor 直接调用

模拟编译器调用构造函数和析构函数

测试代码：

```c++
#include <iostream>
#include <string>
//#include <memory>				 //std::allocator  
using namespace std;

namespace jj02
{

	class A
	{
	public:
		int id;

		A() : id(0)      { cout << "default ctor. this=" << this << " id=" << id << endl; }
		A(int i) : id(i) { cout << "ctor. this=" << this << " id=" << id << endl; }
		~A()             { cout << "dtor. this=" << this << " id=" << id << endl; }
	};

	void test_call_ctor_directly()
	{
		cout << "\ntest_call_ctor_directly().......... \n";

		string* pstr = new string;
		cout << "str= " << *pstr << endl;
		//! pstr->string::string("jjhou");  
		//[Error] 'class std::basic_string<char>' has no member named 'string'
		//! pstr->~string();	//crash -- 其語法語意都是正確的, crash 只因為上一行被 remark 起來嘛.  
		cout << "str= " << *pstr << endl;


		//------------

		A* pA = new A(1);         	//ctor. this=000307A8 id=1
		cout << pA->id << endl;   	//1
		pA->A::A(3);
		cout << pA->id << endl;
		//!	pA->A::A(3);                //in VC6 : ctor. this=000307A8 id=3
		//in GCC : [Error] cannot call constructor 'jj02::A::A' directly

		A::A(5);
		//!	A::A(5);	  				//in VC6 : ctor. this=0013FF60 id=5
		//         dtor. this=0013FF60  	
		//in GCC : [Error] cannot call constructor 'jj02::A::A' directly
		//         [Note] for a function-style cast, remove the redundant '::A'

		cout << pA->id << endl;   	//in VC6 : 3
		//in GCC : 1  	

		delete pA;                	//dtor. this=000307A8 

		//simulate new
		void* p = ::operator new(sizeof(A));
		cout << "p=" << p << endl; 	//p=000307A8
		pA = static_cast<A*>(p);
		pA->A::A(2);
		//!	pA->A::A(2);				//in VC6 : ctor. this=000307A8 id=2
		//in GCC : [Error] cannot call constructor 'jj02::A::A' directly  	

		cout << pA->id << endl;     //in VC6 : 2
		//in GCC : 0  	

		//simulate delete
		pA->~A();					//dtor. this=000307A8 
		::operator delete(pA);		//free()
	}
} //namespace

int main(void)
{
	jj02::test_call_ctor_directly();
	return 0;
}
```

